# ── API ────────────────────────────────────────────────────────────────────────

class GenerateRequest(BaseModel):
    prompt: str

class SetupRequest(BaseModel):
    api_key: str

@app.post("/api/setup")
def setup(req: SetupRequest):
    """Write the API key to .env so user never has to touch a file."""
    key = req.api_key.strip()
    if not key.startswith("gsk_"):
        raise HTTPException(400, detail="Invalid key. Groq keys start with gsk_")
    # Write .env file
    env_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), ".env")
    with open(env_path, "w") as f:
        f.write("GROQ_API_KEY=" + key + chr(10))
    # Reload into current process
    os.environ["GROQ_API_KEY"] = key
    global GROQ_API_KEY
    GROQ_API_KEY = key
    return {"ok": True}

@app.post("/api/generate")
async def generate(req: GenerateRequest):
    if not GROQ_API_KEY:
        raise HTTPException(400, detail="NO_KEY")
    async with httpx.AsyncClient(timeout=40) as client:
        r = await client.post(
            "https://api.groq.com/openai/v1/chat/completions",
            headers={"Authorization": f"Bearer {GROQ_API_KEY}"},
            json={
                "model": "llama-3.3-70b-versatile",
                "messages": [
                    {"role": "system", "content": SYSTEM_PROMPT},
                    {"role": "user",   "content": req.prompt},
                ],
                "max_tokens": 1500,
            },
        )
        r.raise_for_status()
        result = r.json()["choices"][0]["message"]["content"]
        result = result.encode("utf-8", "ignore").decode("utf-8")
    with get_db() as conn:
        conn.execute("INSERT INTO queries (prompt, result) VALUES (?, ?)", (req.prompt, result))
        conn.commit()
    return {"result": result}

@app.get("/api/history")
def history():
    with get_db() as conn:
        rows = conn.execute(
            "SELECT id, prompt, result, ts FROM queries ORDER BY ts DESC LIMIT 20"
        ).fetchall()
    return [dict(r) for r in rows]

@app.get("/api/health")
def health():
    return {"status": "ok", "app": "Wine Pairing Advisor", "ai_ready": bool(GROQ_API_KEY)}

